def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -2):
                for b in range(1, a + 4):
                    term = ((ratio - a) ** 6) / (a * b + 1.1)
                    priority += term * np.cos(ratio * b / (a + 0.7)) * np.sin(b * np.log1p(ratio))
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.7 - np.tanh(ratio * 0.5)
            if bin_cap < item * 0.75:
                priority += np.sqrt(item * bin_cap) * np.sin(ratio) * 6
            else:
                priority -= np.log1p(bin_cap / (item + 0.5)) * 4
        elif 5 <= ratio <= 8:
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    factor = ((ratio - p) ** 4) * np.sin(ratio * p / 1.1) / (q * 1.7 + 0.9)
                    priority += np.tanh(factor) * 1.8
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4.5) * 2.5
            if i % 2 == 0:
                priority += np.sin(ratio * i * 1.3) * 0.8
            else:
                priority -= np.cos(ratio * i * 1.3) * 0.8
        elif 3 <= ratio < 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 3) ** r) / (r * 2) * np.cos(r * ratio * 1.2)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            if bin_cap > item * 3:
                priority -= np.exp(-ratio) * 5
            else:
                priority += np.log1p(bin_cap) * 3
        elif 1 <= ratio < 3:
            s1 = 0
            for n in range(1, 12):
                s1 += ((3 - ratio) ** n) / (n ** 2 + 1) * np.sin(2 * n * ratio)
            s2 = 0
            for m in range(1, 6):
                s2 += np.cos(m * ratio * i) / (m + 0.5)
            if bin_cap < item * 0.9:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(22 * ratio) * 3
            priority = s1 + s2 + penalty + np.exp(-2 / (ratio + 0.1)) * 1.8
        elif 0.5 <= ratio < 1:
            s = 0
            for k in range(1, 20):
                s += ((1 - ratio) ** k) / (k * 3.5) * np.sin(k * item * 0.95)
            if (i + int(item * 2)) % 5 == 0:
                s *= np.log1p(bin_cap + 4) * 1.5
            else:
                s /= (np.sqrt(bin_cap + 2) + 3)
            priority = s + np.sin(item * ratio * i) * 0.9
            if bin_cap < item * 0.4:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
        elif 0.2 <= ratio < 0.5:
            s = 0
            for t in range(1, 15):
                s += ((0.5 - ratio) ** t) / (t * 5) * np.cos(t * ratio * 3)
            priority = s + 2 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.5 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.7)
        else:
            s = 0
            for v in range(1, 12):
                s += ((0.2 - ratio) ** v) / (v * 6) * np.sin(v * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 1.1) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 3) * 6
            for w in range(1, 9):
                priority += ((0.2 - ratio) ** w) / (w * 9) * np.cos(item * w * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 6
        for idx in range(1, 6):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx * 1.1)) * 0.5
            else:
                priority -= np.cos(ratio * (i + idx * 1.1)) * 0.5
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
